xpath.script:
(function () {
    var minQtyEl = document.getElementById('price_break_min_qty_value');
    var minQty = minQtyEl ? (parseFloat(minQtyEl.dataset.minQty) || 0) : 0;
    var errorBox = document.getElementById('price_break_min_qty_error');
    var errorTimeout = null;
    var minQtyLabel = (minQty % 1 === 0 ? parseInt(minQty) : minQty) + ' unité(s)';

    /* ---- Page produit : erreur visible ---- */
    function showPageError() {
        if (!errorBox || minQty <= 0) return;
        errorBox.style.display = 'block';
        clearTimeout(errorTimeout);
        errorTimeout = setTimeout(function () { errorBox.style.display = 'none'; }, 5000);
    }

    function enforcePageMin(input) {
        if (!input || minQty <= 0) return;
        var val = parseFloat(input.value);
        if (isNaN(val) || val < minQty) {
            showPageError();
            input.value = minQty;
            ['input', 'change'].forEach(function (ev) {
                input.dispatchEvent(new Event(ev, { bubbles: true }));
            });
        }
    }

    function applyMinQtyToPageInput(input) {
        if (!input || minQty <= 0) return;
        input.setAttribute('min', minQty);
        if (!input.value || parseFloat(input.value) < minQty) {
            input.value = minQty;
            input.dispatchEvent(new Event('change', { bubbles: true }));
        }
        input.addEventListener('change', function () { enforcePageMin(input); });
        input.addEventListener('blur', function () { enforcePageMin(input); });
        setInterval(function () {
            if (parseFloat(input.value) < minQty) enforcePageMin(input);
        }, 300);
    }

    /* ---- Modal : erreur inline + label ---- */
    function injectModalLabel(input) {
        if (!input || minQty <= 0) return;
        var cell = input.closest('td') || input.closest('.input-group') || input.parentNode;
        if (!cell || cell.querySelector('.pb-modal-label')) return;
        var lbl = document.createElement('div');
        lbl.className = 'pb-modal-label text-center text-muted mt-1';
        lbl.style.fontSize = '0.82em';
        lbl.innerHTML = 'Qté mini : ' + minQtyLabel + '';
        cell.appendChild(lbl);
    }

    function showModalError(input) {
        if (!input || minQty <= 0) return;
        var cell = input.closest('td') || input.closest('.input-group') || input.parentNode;
        if (!cell || cell.querySelector('.pb-modal-error')) return;
        var msg = document.createElement('div');
        msg.className = 'pb-modal-error text-center text-danger mt-1';
        msg.style.fontSize = '0.82em';
        msg.innerHTML = 'Qté minimale : ' + minQtyLabel + '';
        cell.appendChild(msg);
        setTimeout(function () { if (msg.parentNode) msg.parentNode.removeChild(msg); }, 4000);
    }

    function enforceModalMin(input) {
        var val = parseFloat(input.value);
        if (isNaN(val) || val < minQty) {
            input.value = minQty;
            ['input', 'change'].forEach(function (ev) {
                input.dispatchEvent(new Event(ev, { bubbles: true }));
            });
        }
    }

    /* ---- Surveillance continue des modales (robuste contre Owl) ---- */
    if (minQty > 0) {
        setInterval(function () {
            var selectors = '.modal.show input[name="add_qty"],' +
                            '.modal.show .js_quantity,' +
                            '.modal-dialog input[name="add_qty"],' +
                            '.modal-dialog .js_quantity';
            document.querySelectorAll(selectors).forEach(function (input) {
                if (input.type !== 'number') return;

                /* Label (une seule fois) */
                injectModalLabel(input);

                /* Listeners (une seule fois via dataset) */
                if (!input.dataset.pbMinApplied) {
                    input.dataset.pbMinApplied = '1';
                    input.setAttribute('min', minQty);
                    input.addEventListener('change', function () {
                        if (parseFloat(input.value) < minQty) {
                            showModalError(input);
                            enforceModalMin(input);
                        }
                    });
                    input.addEventListener('blur', function () {
                        if (parseFloat(input.value) < minQty) {
                            showModalError(input);
                            enforceModalMin(input);
                        }
                    });
                }

                /* Correction permanente si Owl réinitialise la valeur */
                var val = parseFloat(input.value);
                if (!isNaN(val) && val < minQty) {
                    enforceModalMin(input);
                }
            });
        }, 250);
    }

    /* ---- Page produit au chargement ---- */
    document.addEventListener('DOMContentLoaded', function () {
        applyMinQtyToPageInput(document.querySelector('input[name="add_qty"]'));

        /* Tableau prix dégressifs */
        var rows = document.querySelectorAll('.price-break-row');
        var input = document.querySelector('input[name="add_qty"]');
        var lastValue = input ? input.value : '';

        function highlightMatchingRow(qty) {
            var matched = null;
            rows.forEach(function (row) {
                if (qty >= parseFloat(row.dataset.qty)) matched = row;
            });
            rows.forEach(function (r) { r.classList.remove('price-break-active'); });
            if (matched) matched.classList.add('price-break-active');
        }

        function updateHighlight() {
            if (input && input.value !== lastValue) {
                lastValue = input.value;
                var qty = parseFloat(input.value);
                if (!isNaN(qty)) highlightMatchingRow(qty);
            }
        }

        if (input) {
            input.addEventListener('input', updateHighlight);
            input.addEventListener('change', updateHighlight);
            setInterval(updateHighlight, 200);
            document.querySelectorAll('button, .btn, .fa-plus, .fa-minus, .btn-plus, .btn-minus').forEach(function (btn) {
                btn.addEventListener('click', function () { setTimeout(updateHighlight, 350); });
            });
        }

        rows.forEach(function (row) {
            row.addEventListener('click', function () {
                var qty = Math.max(parseFloat(row.dataset.qty), minQty || 0);
                if (input) {
                    input.value = qty;
                    lastValue = qty.toString();
                    ['input', 'change', 'blur'].forEach(function (ev) {
                        input.dispatchEvent(new Event(ev, { bubbles: true }));
                    });
                }
                highlightMatchingRow(qty);
            });
        });
    });
})();
